let body = $input.item.json.body || $input.item.json;
const accion = body.accion || 'sin_accion';

console.log('Accion recibida:', accion);

return {
  accion,
  datos: body
};

const datos = $input.item.json.datos;
const archivoBase64 = datos.archivo_base64 || datos.archivo;
const nombreArchivo = datos.nombre_archivo || 'estudiantes.xlsx';

if (!archivoBase64) {
  throw new Error('No se recibio archivo base64');
}

const buffer = Buffer.from(archivoBase64, 'base64');

return {
  json: { nombreArchivo },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: nombreArchivo
    }
  }
};

// Procesar estudiantes del Excel
const items = $input.all();
const estudiantes = [];

for (const item of items) {
  const json = item.json;

  // Validar campos obligatorios
  if (!json.cedula || !json.nombres || !json.apellidos) {
    console.log('Fila invalida, saltando:', json);
    continue;
  }

  estudiantes.push({
    cedula: String(json.cedula).trim(),
    nombre: `${json.nombres} ${json.apellidos}`.trim(),
    escuela: json.escuela || json.carrera || 'Sin especificar',
    nivel: json.nivel || '1',
    email: json.email || null,
    edad: json.edad ? parseInt(json.edad) : null
  });
}

console.log(`Procesados ${estudiantes.length} estudiantes`);

return estudiantes.map(est => ({ json: est }));

const items = $input.all();
const total = items.length;

return {
  success: true,
  mensaje: 'Estudiantes procesados exitosamente',
  estudiantes_guardados: total,
  timestamp: new Date().toISOString()
};

return {
  error: true,
  mensaje: 'Accion no reconocida',
  accion_recibida: $input.item.json.accion
};
